const raw = $input.first().json;
const res = Array.isArray(raw) ? (raw[0] || {}) : (raw || {});
const sessionId = res.session_id || res.sessionId || res.id || '';
if (res.ok === false || !sessionId) {
  throw new Error('fn_scan_session failed: ' + JSON.stringify(res).slice(0, 300));
}
const ad = (res.ad && typeof res.ad === 'object' && !Array.isArray(res.ad)) ? res.ad : null;
const adJson = JSON.stringify(ad).replace(/</g, '\u003c');
const html = "<!DOCTYPE html>
<html lang="en">
<head>
<meta charset="UTF-8">
<meta name="viewport" content="width=device-width,initial-scale=1,maximum-scale=1">
<title>Claim your free product</title>
<style>
*{box-sizing:border-box;margin:0;padding:0}
body{font-family:-apple-system,BlinkMacSystemFont,'Segoe UI',sans-serif;background:#0a0a0a;color:#fff;min-height:100vh;display:flex;align-items:center;justify-content:center;padding:20px}
.card{background:#111;border-radius:20px;padding:32px 24px;max-width:380px;width:100%;text-align:center}
.brand{font-size:11px;letter-spacing:3px;text-transform:uppercase;color:#888;margin-bottom:24px}
h1{font-size:26px;font-weight:700;margin-bottom:8px}
.sub{color:#888;font-size:14px;margin-bottom:32px}
input{width:100%;background:#1a1a1a;border:1px solid #333;border-radius:12px;padding:16px;color:#fff;font-size:18px;text-align:center;letter-spacing:2px;outline:none;-webkit-appearance:none}
input:focus{border-color:#fff}
input::placeholder{color:#444;letter-spacing:0}
.btn{width:100%;background:#fff;color:#000;border:none;border-radius:12px;padding:16px;font-size:16px;font-weight:600;cursor:pointer;margin-top:12px;transition:opacity .2s}
.btn:disabled{opacity:0.45;cursor:not-allowed}
.btn-ghost{background:transparent;color:#666;border:none;font-size:13px;margin-top:16px;cursor:pointer;text-decoration:underline}
.error{color:#ff6b6b;font-size:13px;margin-top:10px;min-height:18px}
.info{color:#aaa;font-size:12px;margin-top:10px;min-height:18px}
.hint{color:#555;font-size:11px;margin-top:14px}
.screen{display:none}
.screen.active{display:block}
.otp-input{letter-spacing:8px;font-size:24px}
.ad-creative{position:relative;border-radius:16px;height:230px;margin-bottom:18px;overflow:hidden;display:flex;flex-direction:column;align-items:center;justify-content:center;background:linear-gradient(135deg,#ff7eb3 0%,#ff758c 40%,#7367f0 100%)}
.ad-logo{font-size:30px;font-weight:800;letter-spacing:1px;color:#fff;text-shadow:0 2px 12px rgba(0,0,0,.25)}
.ad-tag{font-size:14px;color:rgba(255,255,255,.92);margin-top:8px;font-weight:500}
.ad-cta{margin-top:14px;font-size:12px;background:rgba(255,255,255,.9);color:#111;padding:7px 16px;border-radius:20px;font-weight:600}
.ad-badge{position:absolute;top:10px;left:10px;font-size:9px;letter-spacing:1px;text-transform:uppercase;background:rgba(0,0,0,.35);color:#fff;padding:3px 8px;border-radius:6px}
.ad-timer{position:absolute;bottom:10px;right:10px;font-size:12px;background:rgba(0,0,0,.45);color:#fff;padding:4px 10px;border-radius:20px;font-variant-numeric:tabular-nums}
.ad-progress{position:absolute;left:0;bottom:0;height:4px;background:rgba(255,255,255,.95);width:0%;transition:width 1s linear}
.done-icon{font-size:48px;margin-bottom:16px}
.privacy-note{font-size:11px;line-height:1.45;color:#666;margin:12px 0 2px;text-align:left}
.privacy-note a{color:#888;text-decoration:underline}
.consent-row{display:flex;align-items:flex-start;gap:8px;margin:8px 0 4px;font-size:12px;line-height:1.4;text-align:left;color:#888}
.consent-row input[type="checkbox"]{margin-top:2px;flex:0 0 auto;accent-color:#ff7eb3}
.consent-row a{color:#888;text-decoration:underline}
</style>
</head>
<body>
<div class="card">
  <div class="screen active" id="s-phone">
    <div class="brand">Covered by Mills</div>
    <h1>&#127873; Free product inside</h1>
    <p class="sub">Enter your number to claim a free product from this machine.</p>
    <input type="tel" id="contact" placeholder="+44 7700 900000" autocomplete="tel">
    <p class="privacy-note">We text you a one-time code to verify your number and prevent misuse of the free service. We store only a one-way <em>hash</em> of your number &mdash; never the number itself. <a href="https://businessforteobaldoselva.github.io/privacy.html" target="_blank" rel="noopener noreferrer">Privacy notice</a></p>
    <label class="consent-row" for="marketing-consent">
      <input type="checkbox" id="marketing-consent">
      <span>Text me offers and news from COVERED (optional &mdash; you'll get your product either way).</span>
    </label>
    <button class="btn" id="btn-send" onclick="sendOtp()">Send verification code &#8594;</button>
    <div class="error" id="err-phone"></div>
    <div class="hint">We'll text you a 6-digit code to confirm it's you.</div>
  </div>

  <div class="screen" id="s-otp">
    <div class="brand">Covered by Mills</div>
    <h1>Enter your code</h1>
    <p class="sub" id="otp-hint">Code sent to your number</p>
    <input type="text" inputmode="numeric" pattern="[0-9]*" id="otp" class="otp-input" placeholder="000000" maxlength="6" autocomplete="one-time-code">
    <button class="btn" id="btn-verify" onclick="verifyOtp()">Verify &#8594;</button>
    <button class="btn-ghost" id="btn-resend" onclick="resendOtp()">Didn't receive it? Resend</button>
    <button class="btn-ghost" id="btn-changenum" onclick="changeNumber()">Wrong number? Change it</button>
    <div class="error" id="err-otp"></div>
    <div class="info" id="info-otp"></div>
  </div>

  <div class="screen" id="s-ad">
    <div class="brand">Sponsored</div>
    <div class="ad-creative">
      <div class="ad-badge">Ad</div>
      <div class="ad-logo">&#10024; GLOW</div>
      <div class="ad-tag">Skincare that loves you back</div>
      <div class="ad-cta">Shop the collection</div>
      <div class="ad-timer" id="ad-timer">5s</div>
      <div class="ad-progress" id="ad-progress"></div>
    </div>
    <button class="btn" id="btn-ad" onclick="adDone()" disabled>Claim your free product &#8594;</button>
    <p class="info" id="ad-hint">Watch the full ad to claim.</p>
  </div>

  <div class="screen" id="s-done">
    <div class="done-icon">&#9989;</div>
    <h1>Enjoy!</h1>
    <p class="sub">Your product is being dispensed. Thanks for engaging!</p>
  </div>

  <div class="screen" id="s-limit">
    <div class="done-icon">&#9203;</div>
    <h1>Come back later</h1>
    <p class="sub">You've reached your monthly limit. See you next month!</p>
  </div>
</div>

<script>
const SESSION_ID = '__SESSION_ID__';
const AD = __AD_JSON__;
const BASE = 'https://coveredbymills.app.n8n.cloud/webhook';
let sessionToken = null;
let currentContact = '';
let sending = false;
let verifying = false;

function clampAdInt(v, min, max, dflt) {
  const n = parseInt(v, 10);
  if (!isFinite(n)) return dflt;
  return Math.min(max, Math.max(min, n));
}
const AD_SECONDS = (AD && typeof AD === 'object') ? clampAdInt(AD.duration_seconds, 2, 30, 5) : 5;

function safeAdGradient(v) {
  if (typeof v !== 'string') return '';
  const s = v.trim();
  if (!s || s.length > 300) return '';
  if (/[<>;{}]/.test(s)) return '';
  if (/url\s*\(|expression|javascript:/i.test(s)) return '';
  if (/^(linear-gradient|radial-gradient|conic-gradient)\s*\(.+\)$/i.test(s)) return s;
  if (/^#[0-9a-fA-F]{3,8}$/.test(s)) return s;
  if (/^rgba?\([\d.,\s%]+\)$/i.test(s)) return s;
  if (/^hsla?\([\d.,\s%deg]+\)$/i.test(s)) return s;
  if (/^[a-zA-Z]{3,20}$/.test(s)) return s;
  return '';
}
function safeAdColor(v) {
  if (typeof v !== 'string') return '';
  const s = v.trim();
  if (/^#[0-9a-fA-F]{3,8}$/.test(s)) return s;
  if (/^rgba?\([\d.,\s%]+\)$/i.test(s)) return s;
  if (/^hsla?\([\d.,\s%deg]+\)$/i.test(s)) return s;
  if (/^[a-zA-Z]{3,20}$/.test(s)) return s;
  return '';
}
function safeAdClickUrl(v) {
  if (typeof v !== 'string') return '';
  const s = v.trim();
  if (!s || s.length > 500) return '';
  if (/[<>"'\s\\]/.test(s)) return '';
  if (!/^https?:\/\//i.test(s)) return '';
  return s;
}

(function renderAd() {
  if (!AD || typeof AD !== 'object') return;
  const logo = document.querySelector('.ad-logo');
  const tag = document.querySelector('.ad-tag');
  const cta = document.querySelector('.ad-cta');
  const creative = document.querySelector('.ad-creative');
  const name = (typeof AD.name === 'string' && AD.name.trim()) ? AD.name.trim()
    : (typeof AD.headline === 'string' && AD.headline.trim()) ? AD.headline.trim() : '';
  if (logo && name) logo.textContent = name;
  if (tag && typeof AD.tagline === 'string' && AD.tagline.trim()) tag.textContent = AD.tagline.trim();
  if (cta && typeof AD.cta_text === 'string' && AD.cta_text.trim()) cta.textContent = AD.cta_text.trim();
  const grad = safeAdGradient(AD.bg_gradient);
  if (creative && grad) creative.style.background = grad;
  const color = safeAdColor(AD.text_color);
  if (color) {
    if (logo) logo.style.color = color;
    if (tag) tag.style.color = color;
  }
  const clickUrl = safeAdClickUrl(AD.click_url);
  if (cta && clickUrl) {
    cta.style.cursor = 'pointer';
    cta.addEventListener('click', function() {
      fireEvent('ad_clicked');
      window.open(clickUrl, '_blank', 'noopener');
    });
  }
})();

function show(id) {
  document.querySelectorAll('.screen').forEach(s => s.classList.remove('active'));
  document.getElementById(id).classList.add('active');
}
function setBtn(id, disabled, text) { const b = document.getElementById(id); if (b) { b.disabled = disabled; if (text) b.textContent = text; } }
function setErr(id, msg) { const el = document.getElementById(id); if (el) el.textContent = msg || ''; }
function setInfo(id, msg) { const el = document.getElementById(id); if (el) el.textContent = msg || ''; }

function changeNumber() {
  setErr('err-phone',''); setInfo('info-otp',''); setErr('err-otp','');
  document.getElementById('otp').value = '';
  show('s-phone');
}

async function sendOtp(isResend) {
  if (sending) return;
  const contact = isResend ? currentContact : document.getElementById('contact').value.trim();
  if (!contact) { setErr('err-phone', 'Please enter your phone number'); return; }
  sending = true;
  const btnId = isResend ? 'btn-resend' : 'btn-send';
  setBtn(btnId, true, 'Sending...');
  setErr(isResend ? 'err-otp' : 'err-phone', '');
  try {
    const r = await fetch(BASE + '/auth/send-otp', {
      method: 'POST', headers: {'Content-Type':'application/json'},
      body: JSON.stringify({ sessionId: SESSION_ID, contact })
    });
    const data = await r.json().catch(() => ({}));
    if (r.ok && data.ok) {
      currentContact = contact;
      document.getElementById('otp').value = '';
      document.getElementById('otp-hint').textContent = 'Code sent to ' + contact;
      if (isResend) { setInfo('info-otp', 'New code sent - use the latest SMS'); }
      else { show('s-otp'); }
    } else {
      setErr(isResend ? 'err-otp' : 'err-phone', data.message || data.reason || 'Could not send a code. Please try again.');
    }
  } catch(e) {
    setErr(isResend ? 'err-otp' : 'err-phone', 'Network error - try again');
  } finally {
    sending = false;
    setBtn('btn-send', false, 'Send verification code →');
    setBtn('btn-resend', false, "Didn't receive it? Resend");
  }
}
async function resendOtp() { setInfo('info-otp', ''); await sendOtp(true); }

async function verifyOtp() {
  if (verifying) return;
  const otp = document.getElementById('otp').value.trim();
  if (otp.length < 4) { setErr('err-otp', 'Enter the full code'); return; }
  verifying = true;
  setBtn('btn-verify', true, 'Verifying...');
  setErr('err-otp', ''); setInfo('info-otp', '');
  try {
    const consentBox = document.getElementById('marketing-consent');
    const marketingConsent = !!(consentBox && consentBox.checked);
    const r = await fetch(BASE + '/auth/verify-otp', {
      method: 'POST', headers: {'Content-Type':'application/json'},
      body: JSON.stringify({ sessionId: SESSION_ID, contact: currentContact, otp, marketing_consent: marketingConsent })
    });
    const data = await r.json().catch(() => ({}));
    if (data.ok) {
      sessionToken = data.sessionToken;
      show('s-ad');
      startAd();
    } else if (data.reason === 'monthly_limit_reached') {
      show('s-limit');
    } else {
      setErr('err-otp', data.message || 'That code did not work. Tap Resend for a new one.');
      setBtn('btn-verify', false, 'Verify →');
    }
  } catch(e) {
    setErr('err-otp', 'Network error - try again');
    setBtn('btn-verify', false, 'Verify →');
  } finally { verifying = false; }
}

function startAd() {
  let remaining = AD_SECONDS;
  const timer = document.getElementById('ad-timer');
  const prog = document.getElementById('ad-progress');
  const btn = document.getElementById('btn-ad');
  const hint = document.getElementById('ad-hint');
  btn.disabled = true;
  timer.textContent = remaining + 's';
  prog.style.width = '0%';
  fireEvent('ad_started');
  const iv = setInterval(function() {
    remaining--;
    prog.style.width = ((AD_SECONDS - remaining) / AD_SECONDS * 100) + '%';
    if (remaining > 0) {
      timer.textContent = remaining + 's';
    } else {
      clearInterval(iv);
      timer.textContent = 'Done';
      prog.style.width = '100%';
      btn.disabled = false;
      hint.textContent = 'Thanks for watching!';
    }
  }, 1000);
}

function fireEvent(type) {
  try {
    fetch(BASE + '/events', {
      method: 'POST', headers: {'Content-Type':'application/json'},
      body: JSON.stringify({ sessionId: SESSION_ID, sessionToken, event: type })
    });
  } catch(e) {}
}

async function adDone() {
  setBtn('btn-ad', true, 'Claiming...');
  fireEvent('ad_completed');
  try {
    const r = await fetch(BASE + '/dispense', {
      method: 'POST', headers: {'Content-Type':'application/json'},
      body: JSON.stringify({ sessionId: SESSION_ID, sessionToken })
    });
    const data = await r.json().catch(() => ({}));
    if (data && data.reason === 'monthly_limit_reached') { show('s-limit'); return; }
  } catch(e) {}
  show('s-done');
}
</script>
</body>
</html>
"
  .replace('__SESSION_ID__', function () { return sessionId; })
  .replace('__AD_JSON__', function () { return adJson; });
return [{ json: { html, sessionId } }];
